INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-how-jain-values-help-modern-families', 'blogs', 'how-jain-values-help-modern-families', 'How Jain values help modern families', 'Jain values such as compassion, restraint, simplicity, and discipline can help families build a calmer daily life.', 'Jain values such as compassion, restraint, simplicity, and discipline can help families build a calmer daily life. Family life today can feel rushed, but Jain values can create steadiness at home. Gentle speech, timely meals, limited consumption, and short family learning routines can help everyone become more mindful. Each family can begin with small steps that suit its tradition and daily rhythm. Family Life family,values,ahimsa,discipline,home', '/article.html?type=blogs&slug=how-jain-values-help-modern-families', 'Family Life', 'family,values,ahimsa,discipline,home', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-01', '2026-05-20', 3, '2026-05-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-teaching-ahimsa-to-children', 'blogs', 'teaching-ahimsa-to-children', 'Teaching Ahimsa to children', 'Ahimsa becomes easier for children to understand through daily behavior, gentle words, food discipline, and acts of kindness.', 'Ahimsa becomes easier for children to understand through daily behavior, gentle words, food discipline, and acts of kindness. Children usually understand Ahimsa better through examples than through definitions alone. Respect for living beings, gentle language, gratitude for food, and habits that reduce harm are all part of the lesson. Parents and teachers can use stories, questions, and small practices to make the idea natural. Children ahimsa,children,parents,teachers,stories', '/article.html?type=blogs&slug=teaching-ahimsa-to-children', 'Children', 'ahimsa,children,parents,teachers,stories', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-02', '2026-05-20', 3, '2026-05-02');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-preparing-for-paryushan-as-a-family', 'blogs', 'preparing-for-paryushan-as-a-family', 'Preparing for Paryushan as a family', 'Family preparation for Paryushan can include simple planning for routine, food discipline, learning, forgiveness, and reflection.', 'Family preparation for Paryushan can include simple planning for routine, food discipline, learning, forgiveness, and reflection. For many families, Paryushan is a period of reflection and discipline. It helps to plan meals, schedules, readings, and childrenâ€™s participation in advance. Local sangh guidance and family elders can help shape a meaningful routine. Always verify dates and specific observances with a local Jain calendar. Festivals paryushan,family,forgiveness,calendar,discipline', '/article.html?type=blogs&slug=preparing-for-paryushan-as-a-family', 'Festivals', 'paryushan,family,forgiveness,calendar,discipline', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-03', '2026-05-20', 3, '2026-05-03');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-jain-food-discipline-in-modern-life', 'blogs', 'jain-food-discipline-in-modern-life', 'Jain food discipline in modern life', 'Jain food discipline can still be followed thoughtfully in busy modern life with planning, awareness, and family support.', 'Jain food discipline can still be followed thoughtfully in busy modern life with planning, awareness, and family support. Jain food discipline is not only about what to eat. It is also a practice of awareness and restraint. Families often need to balance home routines, travel, outside food, and childrenâ€™s needs. Many households follow the discipline in ways shaped by family tradition, health needs, and elder guidance. Food food,discipline,ahimsa,family,travel', '/article.html?type=blogs&slug=jain-food-discipline-in-modern-life', 'Food', 'food,discipline,ahimsa,family,travel', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-04', '2026-05-20', 3, '2026-05-04');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-visiting-a-jain-temple-respectfully', 'blogs', 'visiting-a-jain-temple-respectfully', 'Visiting a Jain temple respectfully', 'Temple visits are more meaningful when done with cleanliness, calmness, humility, and respect for local guidance.', 'Temple visits are more meaningful when done with cleanliness, calmness, humility, and respect for local guidance. A Jain temple is not only a place to see, but a place of reverence and discipline. Before visiting, understand local guidance about dress, cleanliness, food expectations, and photography. For timings, dharamshala, or bhojanshala details, the safest approach is to confirm locally with the temple or trust. Temples temple,visit,discipline,pilgrimage,respect', '/article.html?type=blogs&slug=visiting-a-jain-temple-respectfully', 'Temples', 'temple,visit,discipline,pilgrimage,respect', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-05', '2026-05-20', 3, '2026-05-05');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-building-a-daily-jain-learning-habit', 'blogs', 'building-a-daily-jain-learning-habit', 'Building a daily Jain learning habit', 'A small but steady learning routine can make Jain values more rooted in individual and family life.', 'A small but steady learning routine can make Jain values more rooted in individual and family life. Daily Jain learning does not require long study hours. A few minutes of reading, one thoughtful question, or simple mantra remembrance can be enough to begin. Families can also create one shared weekly learning time and invite children to ask simple questions. Learning learning,daily-practice,family,children,reflection', '/article.html?type=blogs&slug=building-a-daily-jain-learning-habit', 'Learning', 'learning,daily-practice,family,children,reflection', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-06', '2026-05-20', 3, '2026-05-06');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-blogs-why-source-verification-matters-in-community-resources', 'blogs', 'why-source-verification-matters-in-community-resources', 'Why source verification matters in community resources', 'Source verification is essential for trustworthy scholarship, temple, contact, and support information.', 'Source verification is essential for trustworthy scholarship, temple, contact, and support information. Community platforms remain useful only when their information is verified. Old or incomplete details about scholarships, temple visits, trust contacts, or government resources can cause confusion. That is why correction workflows, review steps, and cautious publishing are important on JainWorld. Community verification,resources,community,trust,corrections', '/article.html?type=blogs&slug=why-source-verification-matters-in-community-resources', 'Community', 'verification,resources,community,trust,corrections', 'en', 'published', 'approved', 'JainWorld Editorial', '2026-05-07', '2026-05-20', 3, '2026-05-07');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-why-jains-avoid-root-vegetables', 'food', 'why-jains-avoid-root-vegetables', 'Why Jains avoid root vegetables', 'Many Jain families explain avoiding root vegetables through Ahimsa, care for subtle life, and traditional food discipline.', 'Many Jain families explain avoiding root vegetables through Ahimsa, care for subtle life, and traditional food discipline. Uprooting root vegetables is often associated with greater harm to subtle life forms. Bottle gourd, pumpkin, cabbage, and raw banana are commonly treated as practical alternatives in many homes. root vegetables,ahimsa,food discipline,à¤•à¤‚à¤¦-à¤®à¥‚à¤²', '/article.html?type=food&slug=why-jains-avoid-root-vegetables', 'What not to eat', 'root vegetables,ahimsa,food discipline,à¤•à¤‚à¤¦-à¤®à¥‚à¤²', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-eating-before-sunset', 'food', 'eating-before-sunset', 'Eating before sunset', 'Many Jain families treat eating before sunset as part of time discipline and mindful routine.', 'Many Jain families treat eating before sunset as part of time discipline and mindful routine. This practice is often linked with restraint, care, and a more disciplined daily rhythm. Earlier meals may also feel easier for digestion and routine planning for many people. sunset meal,daily discipline,evening routine,à¤¸à¥‚à¤°à¥à¤¯à¤¾à¤¸à¥à¤¤ à¤¸à¥‡ à¤ªà¤¹à¤²à¥‡ à¤­à¥‹à¤œà¤¨', '/article.html?type=food&slug=eating-before-sunset', 'Daily discipline', 'sunset meal,daily discipline,evening routine,à¤¸à¥‚à¤°à¥à¤¯à¤¾à¤¸à¥à¤¤ à¤¸à¥‡ à¤ªà¤¹à¤²à¥‡ à¤­à¥‹à¤œà¤¨', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-travel-food-checklist', 'food', 'travel-food-checklist', 'Travel food checklist', 'A simple advance checklist can make food discipline more manageable for families during travel.', 'A simple advance checklist can make food discipline more manageable for families during travel. Dry snacks, fruit, simple home food, and light packed options Plan calmly before travel by checking ingredients, meal timing, and available alternatives. Many families value maintaining awareness and restraint even while traveling. Advance planning can reduce confusion, rushed choices, and unnecessary compromise. travel food,checklist,family travel,à¤¯à¤¾à¤¤à¥à¤°à¤¾ à¤­à¥‹à¤œà¤¨', '/article.html?type=food&slug=travel-food-checklist', 'Travel food', 'travel food,checklist,family travel,à¤¯à¤¾à¤¤à¥à¤°à¤¾ à¤­à¥‹à¤œà¤¨', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-jain-food-for-children', 'food', 'jain-food-for-children', 'Jain food for children', 'Simple language, family-friendly options, and patient explanation can help children understand Jain food discipline.', 'Simple language, family-friendly options, and patient explanation can help children understand Jain food discipline. Simple home snacks, fruit, light vegetables, and school-friendly tiffin options Start with small habits and explainable choices rather than rigid instructions. Teaching children kindness, restraint, and awareness around food can become a shared family learning practice. Clear and planned choices can be helpful for school routines, outings, and travel. children,kids food,school meals,family guidance,à¤¬à¤šà¥à¤šà¥‹à¤‚ à¤•à¤¾ à¤­à¥‹à¤œà¤¨', '/article.html?type=food&slug=jain-food-for-children', 'Kids food', 'children,kids food,school meals,family guidance,à¤¬à¤šà¥à¤šà¥‹à¤‚ à¤•à¤¾ à¤­à¥‹à¤œà¤¨', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-festival-fasting-food-guidance', 'food', 'festival-fasting-food-guidance', 'Festival fasting food guidance', 'Food practices during festivals and fasting may vary by family guidance, tradition, and individual capacity.', 'Food practices during festivals and fasting may vary by family guidance, tradition, and individual capacity. Light permitted foods, fruit, limited preparation, and options guided by local practice For stricter observance, family elders, teachers, or local sangh guidance may be more helpful than a generic summary. Many people understand fasting as a discipline of restraint, reflection, and self-observation. Simple planning and lighter preparation can reduce stress during observance days. fasting,festival food,upvas,guidance,à¤‰à¤ªà¤µà¤¾à¤¸', '/article.html?type=food&slug=festival-fasting-food-guidance', 'Fasting', 'fasting,festival food,upvas,guidance,à¤‰à¤ªà¤µà¤¾à¤¸', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-ayambil-basics', 'food', 'ayambil-basics', 'Ayambil basics', 'Ayambil is often associated with simplicity in food, restraint, and spiritual attentiveness.', 'Ayambil is often associated with simplicity in food, restraint, and spiritual attentiveness. Simple permitted ingredients, minimal seasoning, and restrained preparation The exact discipline and method may vary across traditions and family practice. Many people connect this practice with sensory restraint and inward simplicity. Simpler preparation can make the day feel more focused and deliberate. ayambil,fasting,discipline,simple food,à¤†à¤¯à¤‚à¤¬à¤¿à¤²', '/article.html?type=food&slug=ayambil-basics', 'Fasting', 'ayambil,fasting,discipline,simple food,à¤†à¤¯à¤‚à¤¬à¤¿à¤²', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-simple-jain-kitchen-discipline', 'food', 'simple-jain-kitchen-discipline', 'Simple Jain kitchen discipline', 'Many families treat kitchen cleanliness, minimal waste, simplicity, and clarity of ingredients as part of Jain discipline.', 'Many families treat kitchen cleanliness, minimal waste, simplicity, and clarity of ingredients as part of Jain discipline. Small planning steps, fresh ingredients, measured quantity, and modest preparation can be helpful. Care and restraint around food are often treated as a practical extension of Jain values. An organized kitchen can help families manage time, cost, and wastage more effectively. kitchen discipline,daily routine,simple cooking,à¤°à¤¸à¥‹à¤ˆ à¤…à¤¨à¥à¤¶à¤¾à¤¸à¤¨', '/article.html?type=food&slug=simple-jain-kitchen-discipline', 'Daily discipline', 'kitchen discipline,daily routine,simple cooking,à¤°à¤¸à¥‹à¤ˆ à¤…à¤¨à¥à¤¶à¤¾à¤¸à¤¨', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-reading-packaged-food-labels', 'food', 'reading-packaged-food-labels', 'Reading packaged food labels', 'Reading ingredients, additives, and unclear terms on packaged food can be a useful skill for Jain families.', 'Reading ingredients, additives, and unclear terms on packaged food can be a useful skill for Jain families. If an ingredient is unclear, it is usually better to check a trusted source or the manufacturerâ€™s own information. Ingredient awareness can become one practical way of living food discipline more carefully. Label-reading can also help with identifying allergens, additives, and unwanted ingredients. packaged food,labels,ingredients,shopping,à¤²à¥‡à¤¬à¤² à¤ªà¤¢à¤¼à¤¨à¤¾', '/article.html?type=food&slug=reading-packaged-food-labels', 'Daily diet', 'packaged food,labels,ingredients,shopping,à¤²à¥‡à¤¬à¤² à¤ªà¤¢à¤¼à¤¨à¤¾', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-jain-food-during-travel-abroad', 'food', 'jain-food-during-travel-abroad', 'Jain food during travel abroad', 'During overseas travel, advance planning, simple choices, and polite communication can be helpful for many families.', 'During overseas travel, advance planning, simple choices, and polite communication can be helpful for many families. Fruit, bread alternatives, plain grains, packaged fallback snacks, and simple cooked foods When menus are unfamiliar or language is a barrier, simpler options with fewer ingredients may be easier to verify. Maintaining awareness and restraint while traveling remains important for many Jain families. Advance planning can reduce dependence on uncertain food choices. travel abroad,foreign travel,jain food,packing,à¤µà¤¿à¤¦à¥‡à¤¶ à¤¯à¤¾à¤¤à¥à¤°à¤¾ à¤­à¥‹à¤œà¤¨', '/article.html?type=food&slug=jain-food-during-travel-abroad', 'Travel food', 'travel abroad,foreign travel,jain food,packing,à¤µà¤¿à¤¦à¥‡à¤¶ à¤¯à¤¾à¤¤à¥à¤°à¤¾ à¤­à¥‹à¤œà¤¨', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
INSERT OR REPLACE INTO search_index (id, content_type, source_id, title, summary, body, url, category, tags, language, status, review_status, source_name, published_at, updated_at, search_weight, created_at) VALUES ('search-index-food-family-friendly-jain-meal-planning', 'food', 'family-friendly-jain-meal-planning', 'Family-friendly Jain meal planning', 'When planning meals for a family, it can help to balance simplicity, childrenâ€™s needs, elder guidance, and time discipline.', 'When planning meals for a family, it can help to balance simplicity, childrenâ€™s needs, elder guidance, and time discipline. A simple weekly list, seasonal vegetables, permitted staples, fruit, and light snacks A little advance planning can reduce rushed choices and make meals calmer for the whole family. Careful planning can support both awareness and cooperation within the family. Planned meals can make it easier to manage time, cost, and food wastage. family meal planning,daily diet,children,elders,à¤­à¥‹à¤œà¤¨ à¤¯à¥‹à¤œà¤¨à¤¾', '/article.html?type=food&slug=family-friendly-jain-meal-planning', 'Daily diet', 'family meal planning,daily diet,children,elders,à¤­à¥‹à¤œà¤¨ à¤¯à¥‹à¤œà¤¨à¤¾', 'en', 'published', 'verified', 'JainWorld', NULL, NULL, 4, '2026-01-01');
